def _forced_fallback(inputs: dict[str, Any]) -> bool:
    return parent._forced_fallback(inputs)

def _use_lowq_tail_row16(inputs: dict[str, Any]) -> bool:
    q_rows = int(inputs['Q'])
    m_rows = int(inputs['M'])
    return int(inputs['B']) == 1 and q_rows in LOWQ_Q_VALUES and (65536 <= m_rows < 131072) and (int(inputs['D']) == D_STATIC) and (int(inputs['K']) == K_MAX) and row16._tcgen05_capable_arch()

def selected_route(inputs: dict[str, Any]) -> str:
    if _forced_fallback(inputs):
        return parent.selected_route(inputs)
    if _use_lowq_tail_row16(inputs):
        return ROUTE_LOWQ_TAIL_ROW16
    return parent.selected_route(inputs)

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def _selected_guard(inputs: dict[str, Any], route: str, parent_info: dict[str, Any] | None) -> str:
    if _forced_fallback(inputs):
        return 'force_fallback metadata/env'
    if route == ROUTE_LOWQ_TAIL_ROW16:
        return SHAPE_DISPATCH_REGISTRY[0]['guard']
    if parent_info is not None:
        return str(parent_info.get('selected_guard', 'round57 guard miss; delegate to parent'))
    return 'round57 guard miss; delegate to parent'

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    route = selected_route(inputs)
    if route != ROUTE_LOWQ_TAIL_ROW16:
        info = dict(parent.route_info(inputs))
        guard_order = list(info.get('guard_order', []))
        info['guard_order'] = [SHAPE_DISPATCH_REGISTRY[0]['shape_key'], *guard_order]
        info['selected_guard'] = _selected_guard(inputs, route, info)
        return info
    parent_info = parent.route_info(inputs)
    return {'route': route, 'parent_route': parent_info['route'], 'route_kind': 'specialized', 'coverage_class': 'performance_route_lowq_tail_row16', 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': [entry['shape_key'] for entry in SHAPE_DISPATCH_REGISTRY], 'forced_fallback': False, 'selected_guard': _selected_guard(inputs, route, parent_info), 'fallback': None}

def route_trace_entry(label: str, inputs: dict[str, Any]) -> dict[str, Any]:
    info = route_info(inputs)
    return {'label': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), **info}

def coverage_route_trace() -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for category, shapes in LOWQ_COVERAGE_CATEGORY_SHAPES.items():
        for shape in shapes:
            inputs = dict(shape['params'])
            if category == 'forced_fallback':
                inputs['force_fallback'] = True
            entry = route_trace_entry(str(shape['label']), inputs)
            entry['category'] = category
            entries.append(entry)
    return entries

def _launch_lowq_tail_row16(inputs: dict[str, Any]) -> dict[str, Any]:
    import torch
    if not row16._KERNELS:
        row16._KERNELS.update(row16._compile_kernels())
    bsz = int(inputs['B'])
    q_rows = int(inputs['Q'])
    m_rows = int(inputs['M'])
    k = int(inputs['K'])
    num_q_tiles = math.ceil(q_rows / row16.BLOCK_Q)
    total_m_tiles = math.ceil(m_rows / row16.BLOCK_M)
    partial_dist, partial_idx = _mma._scratch(inputs, row16.SPLIT_M, num_q_tiles)
    row16._KERNELS['partial'].launch(grid=(bsz * num_q_tiles * row16.SPLIT_M, 1, 1), block=(row16.THREADS, 1, 1), args=[inputs['queries'], inputs['database'], partial_dist, partial_idx, bsz, q_rows, m_rows, row16.SPLIT_M, num_q_tiles, total_m_tiles], shared_mem=row16.SMEM_BYTES)
    row16._KERNELS['merge'].launch(grid=(bsz * q_rows, 1, 1), block=(_mma.MERGE_THREADS, 1, 1), args=[partial_dist, partial_idx, inputs['out_distances'], inputs['out_indices'], bsz, q_rows, k, row16.SPLIT_M, num_q_tiles], shared_mem=_mma.MERGE_SMEM_BYTES)
    return {'distances': inputs['out_distances'], 'indices': inputs['out_indices']}

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    if not _forced_fallback(inputs) and _use_lowq_tail_row16(inputs):
        return _launch_lowq_tail_row16(inputs)
    return parent.launch_for_eval(inputs)

def knn_search_compile_and_launch_lowq_tail_row16(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    selected = shapes
    if selected is None:
        selected = LOWQ_TAIL_ROW16_PERFORMANCE_SHAPES if benchmark else LOWQ_TAIL_ROW16_CORRECTNESS_SHAPES
    result = evaluate(launch_for_eval, shapes=selected, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result

def knn_search_compile_and_launch_registered_default(*, benchmark: bool=True) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    shapes = DEFAULT_REGISTRY_PERFORMANCE_SHAPES if benchmark else DEFAULT_REGISTRY_CORRECTNESS_SHAPES
    result = evaluate(launch_for_eval, shapes=shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result
